67:     @Override
68:     protected KafkaEndpoint createEndpoint(String uri, String remaining, Map<String, Object> parameters) throws Exception {
69:         if (ObjectHelper.isEmpty(remaining)) {
70:             throw new IllegalArgumentException("Topic must be configured on endpoint using syntax kafka:topic");
71:         }
72: 
73:         // extract the endpoint additional properties map
74:         final Map<String, Object> endpointAdditionalProperties
75:                 = PropertiesHelper.extractProperties(parameters, "additionalProperties.");
76: 
77:         KafkaEndpoint endpoint = new KafkaEndpoint(uri, this);
78: 
79:         KafkaConfiguration copy = getConfiguration().copy();
80:         endpoint.setConfiguration(copy);
81: 
82:         setProperties(endpoint, parameters);
83: 
84:         if (endpoint.getConfiguration().getSslContextParameters() == null) {
85:             endpoint.getConfiguration().setSslContextParameters(retrieveGlobalSslContextParameters());
86:         }
87: 
88:         if (!endpointAdditionalProperties.isEmpty()) {
89:             Map<String, Object> map = new HashMap<>();
90:             // resolve parameter values from the values (#bean / #class etc)
91:             PropertyBindingSupport.bindProperties(getCamelContext(), map, endpointAdditionalProperties);
92:             // overwrite the additional properties from the endpoint
93:             endpoint.getConfiguration().getAdditionalProperties().putAll(map);
94:         }
95: 
96:         // If a topic is not defined in the KafkaConfiguration (set as option parameter) but only in the uri,
97:         // it can happen that it is not set correctly in the configuration of the endpoint.
98:         // Therefore, the topic is added after setProperties method
99:         // and a null check to avoid overwriting a value from the configuration.
100:         if (endpoint.getConfiguration().getTopic() == null) {
101:             endpoint.getConfiguration().setTopic(remaining);
102:         }
103: 
104:         return endpoint;
105:     }
